/**
 * @generated by @flusk/cli — cli-command recipe
 * CLI command: flusk alerts-test
 */
import { Command } from 'commander';
import chalk from 'chalk';
import { getDb } from '@flusk/resources';

export const alertsTestCommand = new Command('alerts-test')
  .description('Send a test alert to a channel')
  .requiredOption('--name <name>', 'Channel name to test')
  .action(async (opts) => {
    const db = getDb();
    const { AlertChannelRepository } = await import('@flusk/resources');
    const { alerting } = await import('@flusk/business-logic');

    const channels = AlertChannelRepository.listAlertChannels(db);
    const channel = channels.find((c) => c.name === opts.name);

    if (!channel) {
      console.error(chalk.red(`Channel "${opts.name}" not found`));
      process.exit(1);
    }

    const testAlert = {
      alertType: 'budget_warning' as const,
      severity: 'info' as const,
      title: 'Test Alert',
      message: 'This is a test alert from flusk alerts-test.',
    };

    const result = await alerting.sendToChannel(testAlert, channel);
    if (result.delivered) {
      console.log(chalk.green(`✅ Test alert delivered to "${channel.name}"`));
    } else {
      console.error(chalk.red(`❌ Failed: ${result.error}`));
      process.exit(1);
    }
  });
